{"slots":[{"id":"arr","type":"array","label":"Sorted Array"}],"inputs":[{"label":"Target","default":"7"}],"code":"class Playground {
  async run(inputs) {
    const data = [1, 3, 5, 8, 12, 15, 18, 21, 25, 30];
    const target = parseInt(inputs.Target);
    await this.arr.init(data);

    let low = 0;
    let high = data.length - 1;

    while (low <= high) {
      // Reset previous highlights
      await this.arr.highlightRange(0, data.length - 1, null);
      // Highlight the current search window in Cyan
      await this.arr.highlightRange(low, high, 'cyan');

      let mid = Math.floor(low + (high - low) / 2);
      // Highlight the pivot/mid in Pink
      await this.arr.highlight(mid, 'pink');

      this.log(`Searching range [${low}, ${high}]. Midpoint index ${mid} has value ${data[mid]}`);
      await this.await();

      if (data[mid] === target) {
        await this.arr.highlight(mid, 'emerald');
        this.log(`Success! Target ${target} found at index ${mid}.`);
        return;
      }

      if (data[mid] < target) {
        this.log(`${data[mid]} < ${target}. Discarding left half.`);
        low = mid + 1;
      } else {
        this.log(`${data[mid]} > ${target}. Discarding right half.`);
        high = mid - 1;
      }
      await this.await();
    }

    this.log(`Target ${target} not found in the array.`);
  }
}"}

